import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { PromptService, Prompt } from '../prompt.service';

@Component({
  selector: 'app-prompt-list',
  standalone: false,
  template: `
    <h2>All Prompts</h2>
    <div *ngIf="loading" class="loading">Loading...</div>
    <div *ngIf="!loading && prompts.length === 0" class="empty-state">
      <p>No prompts yet.</p>
      <a routerLink="/new" class="btn">Create First Prompt</a>
    </div>
    <div *ngIf="!loading && prompts.length > 0">
      <div *ngFor="let prompt of prompts" class="card" [routerLink]="['/prompts', prompt.id]">
        <h3>{{ prompt.title }}</h3>
        <span class="badge" [ngClass]="getComplexityClass(prompt.complexity)">
          Complexity: {{ prompt.complexity }}/10
        </span>
        <p class="view-count">Views: {{ prompt.view_count }}</p>
      </div>
    </div>
  `,
  styles: [`:host { display: block; }`]
})
export class PromptListComponent implements OnInit {
  prompts: Prompt[] = [];
  loading = true;

  constructor(private promptService: PromptService) { }

  ngOnInit(): void {
    this.promptService.getPrompts().subscribe({
      next: (res) => {
        this.prompts = res.prompts;
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }

  getComplexityClass(level: number): string {
    if (level <= 3) return 'badge-low';
    if (level <= 7) return 'badge-medium';
    return 'badge-high';
  }
}
